"use client";

import { motion, useScroll, useTransform, AnimatePresence } from "framer-motion";
import { useEffect, useState, useRef } from "react";
import Image from "next/image";
import { Building2, MapPin, Maximize, ChevronLeft, ChevronRight } from "lucide-react";

/* ── Marquee Text Strip ───────────────────────────────── */
function MarqueeStrip() {
  const items = [
    "67 STOREYS", "960 LUXURY UNITS", "118M INFINITY POOL", "SKY WELLNESS",
    "CONCIERGE SERVICES", "LINK BRIDGE TO PAVILION KL", "FREEHOLD", "BUKIT BINTANG",
    "CORPORATE SUITES",
  ];
  return (
    <div className="absolute bottom-[20%] left-0 w-full z-20 overflow-hidden opacity-30 pointer-events-none mix-blend-overlay">
      <div className="marquee-track flex whitespace-nowrap gap-16" style={{ willChange: "transform" }}>
        {[...items, ...items].map((item, i) => (
          <span key={i} className="text-[10px] uppercase tracking-[0.4em] text-white/50 font-medium flex items-center gap-8">
            {item} <span className="w-1.5 h-1.5 rounded-full bg-gold/80 shadow-[0_0_10px_rgba(196,162,101,0.5)] inline-block" />
          </span>
        ))}
      </div>
    </div>
  );
}

/* ── Hero Stats HUD (Compact) ─────────────────────────── */
function HeroStats() {
  const stats = [
    { icon: Building2, label: "Storeys", value: "67", suffix: "" },
    { icon: MapPin, label: "Location", value: "Bukit Bintang", suffix: "" },
    { icon: Maximize, label: "Square ft", value: "504 - 1272", suffix: " sq.ft" },
  ];
  return (
    <motion.div
      initial={{ opacity: 0, y: 50 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 1.2, delay: 1, ease: "easeOut" }}
      className="absolute bottom-10 sm:bottom-16 left-1/2 -translate-x-1/2 z-30 pointer-events-auto w-[95%] sm:w-auto max-w-[95vw]"
    >
      <motion.div
        animate={{ y: [-3, 3, -3] }}
        transition={{ duration: 6, repeat: Infinity, ease: "easeInOut" }}
        className="flex flex-row flex-wrap items-center justify-center sm:flex-row gap-4 sm:gap-8 bg-[#0e0c14]/60 backdrop-blur-[12px] px-6 py-4 rounded-3xl min-[430px]:rounded-full border border-gold/20 shadow-[0_10px_40px_rgba(0,0,0,0.8)] hover:border-gold/50 transition-all duration-500"
      >
        {stats.map((stat, i) => (
          <div key={i} className={`flex items-center gap-3 group relative flex-1 min-[430px]:flex-none justify-center ${i !== 0 ? 'border-l border-white/10 pl-4 min-[430px]:border-none min-[430px]:pl-0' : ''}`}>
            <div className="relative w-8 h-8 rounded-full bg-[#1a1820] shrink-0 flex items-center justify-center border border-gold/30 group-hover:bg-gold/20 transition-all duration-500 overflow-hidden">
              <stat.icon className="w-4 h-4 text-gold group-hover:text-white transition-colors duration-500 relative z-10" />
            </div>
            <div className="flex flex-col text-left">
              <span className="text-sm sm:text-lg font-heading font-black text-white leading-none group-hover:text-gold transition-colors block whitespace-nowrap">
                {stat.value}{stat.suffix}
              </span>
              <span className="text-[9px] sm:text-[10px] sm:mt-0.5 uppercase tracking-[0.2em] text-gold/70 block font-medium whitespace-nowrap">
                {stat.label}
              </span>
            </div>
            {i < stats.length - 1 && <div className="hidden sm:block w-px h-8 bg-gradient-to-b from-transparent via-white/20 to-transparent ml-4" />}
          </div>
        ))}
      </motion.div>
    </motion.div>
  );
}

/* ── Main Hero Component ──────────────────────────────── */
export default function Hero() {
  const containerRef = useRef<HTMLDivElement>(null);
  const { scrollYProgress } = useScroll({ target: containerRef, offset: ["start start", "end start"] });
  const heroOpacity = useTransform(scrollYProgress, [0, 0.7], [1, 0]);
  const textY = useTransform(scrollYProgress, [0, 0.5], [0, 100]);

  const images = [
    "/page_3_img_1.jpeg",
    "/page_4_img_1.jpeg",
    "/page_6_img_1.jpeg",
    "/page_8_img_1.jpeg",
    "/page_9_img_1.jpeg",
  ];
  
  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % images.length);
    }, 5000);
    return () => clearInterval(timer);
  }, [images.length]);

  const nextSlide = () => setCurrentIndex((prev) => (prev + 1) % images.length);
  const prevSlide = () => setCurrentIndex((prev) => (prev - 1 + images.length) % images.length);

  return (
    <section id="hero" ref={containerRef} className="relative w-full min-h-[100dvh] sm:min-h-screen overflow-hidden bg-[#0e0f1a]">
      {/* ▸ Layer 0: High-Impact Animated Background */}
      <div className="absolute inset-0 z-0 overflow-hidden">
        <AnimatePresence mode="wait">
          <motion.div
            key={currentIndex}
            initial={{ opacity: 0, scale: 1.05 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            transition={{ duration: 1.5, ease: "easeInOut" }}
            className="absolute inset-0"
          >
            <Image
              src={images[currentIndex]}
              alt={`Slide ${currentIndex + 1}`}
              fill
              priority
              sizes="100vw"
              quality={100}
              className="object-cover"
            />
          </motion.div>
        </AnimatePresence>

        <div className="absolute inset-0 bg-gradient-to-b from-[#0e0f1a]/60 via-transparent to-[#0e0f1a]/90 mix-blend-multiply" />
        <div className="absolute inset-0 bg-gradient-to-l from-[#0e0f1a]/80 via-transparent to-transparent pointer-events-none" />
      </div>

      {/* Slider Controls */}
      <div className="absolute top-1/2 -translate-y-1/2 left-4 md:left-8 z-30">
        <button onClick={prevSlide} className="w-12 h-12 rounded-full border border-gold/50 bg-black/30 backdrop-blur flex items-center justify-center text-gold hover:bg-gold/40 hover:scale-110 transition-all duration-300">
          <ChevronLeft size={28} />
        </button>
      </div>
      <div className="absolute top-1/2 -translate-y-1/2 right-4 md:right-8 z-30">
        <button onClick={nextSlide} className="w-12 h-12 rounded-full border border-gold/50 bg-black/30 backdrop-blur flex items-center justify-center text-gold hover:bg-gold/40 hover:scale-110 transition-all duration-300">
          <ChevronRight size={28} />
        </button>
      </div>

      {/* ▸ Main Content Overlay */}
      <div className="relative z-10 flex flex-col items-end justify-center min-h-screen px-4 sm:px-16 md:px-24 py-16 sm:py-20 pointer-events-none pb-32">
        <motion.div
          style={{ y: textY, opacity: heroOpacity }}
          className="w-full relative z-10 flex flex-col items-end text-right"
        >
          <motion.h1
            initial={{ opacity: 0, x: 50 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 1.5, ease: [0.16, 1, 0.3, 1] }}
            className="text-[12vw] sm:text-6xl md:text-7xl lg:text-[7rem] leading-[0.9] font-heading font-black text-white tracking-tighter drop-shadow-[0_4px_12px_rgba(0,0,0,1)] whitespace-nowrap"
          >
            <span className="drop-shadow-[0_0_30px_rgba(0,0,0,0.8)] block">EFFORTLESS</span>
            <span className="inline-block relative gold-gradient-text drop-shadow-[0_0_15px_rgba(196,162,101,0.5)]">
              LIVING
            </span>
          </motion.h1>

          <motion.p
            initial={{ opacity: 0, x: 50 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.8, duration: 1.5, ease: "easeOut" }}
            className="mt-4 md:mt-8 text-xs sm:text-lg md:text-2xl uppercase tracking-[0.3em] font-extrabold flex items-center gap-2 sm:gap-4 text-white"
          >
            <span className="w-8 sm:w-16 h-[2px] bg-gradient-to-r from-transparent to-gold" />
            <span className="bg-gradient-to-r from-white to-gold/80 text-transparent bg-clip-text drop-shadow-[0_4px_10px_rgba(0,0,0,1)]">
              PAVILION SQUARE
            </span>
          </motion.p>
        </motion.div>
      </div>

      <MarqueeStrip />
      <HeroStats />
    </section>
  );
}
